class Temperature:
    def __init__(self, celsius=0.0):
        # Assign through the celsius property so validation runs here too.
        ...

    # Define a celsius property (getter + setter) that validates the value,
    # and a read-only fahrenheit property.

exercises.solution_code:
class Temperature:
    def __init__(self, celsius=0.0):
        self.celsius = celsius

    @property
    def celsius(self):
        return self._celsius

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError("temperature below absolute zero")
        self._celsius = value

    @property
    def fahrenheit(self):
        return self._celsius * 9 / 5 + 32

