exercises.solution_code:
class Rectangle:
    def __init__(self, width, height):
        self.width = width
        self.height = height

    @property
    def area(self):
        return self.width * self.height

class Positive:
    """A data descriptor that allows only positive numbers."""

    def __set_name__(self, owner, name):
        # Derive a private per-instance storage key from the attribute name.
        self.storage_name = "_" + name
        self.public_name = name

    def __get__(self, instance, owner=None):
        if instance is None:
            return self
        return getattr(instance, self.storage_name)

    def __set__(self, instance, value):
        if value <= 0:
            raise ValueError(f"{self.public_name} must be positive")
        setattr(instance, self.storage_name, value)


class Order:
    price = Positive()
    quantity = Positive()

    def __init__(self, price, quantity):
        self.price = price
        self.quantity = quantity

class DataField:
    """A DATA descriptor: defines both __get__ and __set__.

    Because it is a data descriptor, it takes precedence over an entry of the
    same name in the instance __dict__.
    """

    def __set_name__(self, owner, name):
        self.storage_name = "_" + name

    def __get__(self, instance, owner=None):
        if instance is None:
            return self
        return getattr(instance, self.storage_name, "data-default")

    def __set__(self, instance, value):
        setattr(instance, self.storage_name, value)


class NonDataField:
    """A NON-DATA descriptor: defines only __get__.

    Because it has no __set__, an instance __dict__ entry of the same name
    shadows it.
    """

    def __get__(self, instance, owner=None):
        if instance is None:
            return self
        return "non-data-default"


class Model:
    data = DataField()
    non_data = NonDataField()
